 11→function trimString(input: unknown): string | undefined {
 12→  if (typeof input !== "string") return undefined;
 13→  const trimmed = input.trim();
 14→  return trimmed || undefined;
 15→}
 16→
 17→function hasValue(input: unknown): boolean {
 18→  if (typeof input === "string") return Boolean(input.trim());
 19→  if (typeof input === "number") return Number.isFinite(input);
 20→  if (typeof input === "boolean") return true;
 21→  if (Array.isArray(input)) return input.length > 0;
 22→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 23→  return false;
 24→}
 25→
 26→function normalizeDetailsForCategory(category: SubmissionCategory, raw: SubmissionDetails): SubmissionDetails {
 27→  return getVertical(category).normalizeDetails(raw);
 28→}
 29→
 30→export function canonicalizeEnrichField(field: string): string {
 31→  return field === "merchantId"
 32→    ? "merchantIdByProvider"
 33→    : field === "hasCashAvailable"
 34→      ? "hasMin50000XafAvailable"
 35→      : field === "hours"
 36→        ? "openingHours"
 37→        : field === "isOnCall" || field === "onDuty"
 38→          ? "isOnDuty"
 39→          : field;
 40→}
 41→
 42→function mergeDetails(base: SubmissionDetails, incoming: SubmissionDetails): SubmissionDetails {
 43→  const merged: SubmissionDetails = { ...base };
 44→  const entries = Object.entries(incoming) as Array<[string, unknown]>;
 45→  for (const [key, value] of entries) {
 46→    if (!hasValue(value)) continue;
 47→    if (Array.isArray(value)) {
 48→      merged[key] = value;
 49→      continue;
 50→    }
 51→    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
 52→      const prev = merged[key];
 53→      if (typeof prev === "object" && prev !== null && !Array.isArray(prev)) {
 54→        merged[key] = { ...(prev as Record<string, unknown>), ...(value as Record<string, unknown>) };
 55→      } else {
 56→        merged[key] = value;
 57→      }
 58→      continue;
 59→    }
 60→    merged[key] = value;
 61→  }
 62→  return merged;
 63→}
