 65→export function listMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
 66→  const normalized = normalizeDetailsForCategory(category, details);
 67→  return getVertical(category).enrichableFields.filter((field) => !hasValue(normalized[field]));
 68→}
