 70→export function listCreateMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
 71→  const normalized = normalizeDetailsForCategory(category, details);
 72→  return getVertical(category).createRequiredFields.filter((field) => !hasValue(normalized[field]));
 73→}
