 80→export function filterEnrichDetails(category: SubmissionCategory, details: SubmissionDetails): SubmissionDetails {
 81→  const filtered: SubmissionDetails = {};
 82→  for (const [field, value] of Object.entries(details)) {
 83→    if (!hasValue(value)) continue;
 84→    if (!isEnrichFieldAllowed(category, field)) continue;
 85→    filtered[field] = value;
 86→  }
 87→  return filtered;
 88→}
