 90→export function eventToProjectedPoint(event: PointEvent): ProjectedPoint {
 91→  const details = normalizeDetailsForCategory(event.category, event.details ?? {});
 92→  const gaps = listMissingFields(event.category, details);
 93→  return {
 94→    id: event.pointId,
 95→    pointId: event.pointId,
 96→    category: event.category,
 97→    location: event.location,
 98→    details,
 99→    photoUrl: event.photoUrl,
100→    createdAt: event.createdAt,

100→    createdAt: event.createdAt,
101→    updatedAt: event.createdAt,
102→    source: event.source,
103→    externalId: event.externalId,
104→    gaps,
