110→export function projectPointsFromEvents(events: PointEvent[]): ProjectedPoint[] {
111→  const groups = new Map<string, ProjectedPoint>();
112→  const sorted = [...events].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
113→  for (const event of sorted) {
114→    const normalizedDetails = normalizeDetailsForCategory(event.category, event.details ?? {});
115→    const existing = groups.get(event.pointId);
116→    if (!existing) {
117→      groups.set(
118→        event.pointId,
119→        {
120→          id: event.pointId,
121→          pointId: event.pointId,
122→          category: event.category,
123→          location: event.location,
124→          details: normalizedDetails,
125→          photoUrl: event.photoUrl,
126→          createdAt: event.createdAt,
127→          updatedAt: event.createdAt,
128→          source: event.source,
129→          externalId: event.externalId,
130→          gaps: listMissingFields(event.category, normalizedDetails),
131→          eventsCount: 1,
132→          eventIds: [event.id],
133→        },
134→      );
135→      continue;
136→    }
137→
138→    existing.category = event.category;
139→    existing.location = event.location ?? existing.location;
140→    existing.details = mergeDetails(existing.details, normalizedDetails);
141→    existing.updatedAt = event.createdAt;
142→    existing.eventsCount += 1;
143→    existing.eventIds.push(event.id);
144→    if (event.photoUrl) existing.photoUrl = event.photoUrl;
145→    if (event.source) existing.source = event.source;
146→    if (event.externalId) existing.externalId = event.externalId;
147→    existing.gaps = listMissingFields(existing.category, existing.details);
148→  }
149→
150→  return Array.from(groups.values()).sort(
151→    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
152→  );
153→}
