179→export function mergePointEventsWithLegacy(pointEvents: PointEvent[], legacySubmissions: LegacySubmission[]): PointEvent[] {
180→  const merged = [...pointEvents];
181→  const seen = new Set(merged.map((item) => item.id));
182→  for (const legacy of legacySubmissions) {
183→    const converted = legacySubmissionToCreateEvent(legacy);
184→    if (seen.has(converted.id)) continue;
185→    merged.push(converted);
186→    seen.add(converted.id);
187→  }
188→  return merged;
189→}
