  4→export interface ConfidenceFactors {
  5→  recency: number;
  6→  sourceCount: number;
  7→  photoEvidence: number;
  8→  gpsAccuracy: number;
  9→  reviewerApproval: number;
 10→  fieldCompleteness: number;
 11→}
 12→
 13→const MS_PER_DAY = 24 * 60 * 60 * 1000;
 14→
 15→function hasValue(input: unknown): boolean {
 16→  if (typeof input === "string") return Boolean(input.trim());
 17→  if (typeof input === "boolean") return true;
 18→  if (typeof input === "number") return Number.isFinite(input);
 19→  if (Array.isArray(input)) return input.length > 0;
 20→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 21→  return false;
 22→}
 23→
 24→function toFiniteDate(input: string): Date | null {
 25→  const parsed = new Date(input);
 26→  if (Number.isNaN(parsed.getTime())) return null;
 27→  return parsed;
 28→}
 29→
 30→function clampScore(value: number): number {
 31→  if (!Number.isFinite(value)) return 0;
 32→  return Math.min(100, Math.max(0, Math.round(value)));
 33→}
 34→
 35→function getRecencyScore(updatedAt: string, referenceDate: Date): number {
 36→  const updatedDate = toFiniteDate(updatedAt);
 37→  if (!updatedDate) return 0;
 38→  const daysSinceUpdate = Math.max(0, (referenceDate.getTime() - updatedDate.getTime()) / MS_PER_DAY);
 39→
 40→  if (daysSinceUpdate <= 7) return 25;
 41→  if (daysSinceUpdate <= 14) return 22;
 42→  if (daysSinceUpdate <= 30) return 18;
 43→  if (daysSinceUpdate <= 60) return 12;
 44→  if (daysSinceUpdate <= 90) return 6;
 45→  return 0;
 46→}
 47→
 48→function getSourceCountScore(eventsCount: number): number {
 49→  if (eventsCount >= 5) return 20;
 50→  if (eventsCount >= 3) return 15;
 51→  if (eventsCount >= 2) return 10;
 52→  return 5;
 53→}
 54→
 55→function getPhotoEvidenceScore(point: ProjectedPoint): number {
 56→  let score = 0;
 57→  const details = point.details as SubmissionDetails;
 58→  if (point.photoUrl) score += 10;
 59→  if (details.hasSecondaryPhoto === true) score += 5;
 60→
 61→  const fraudCheck = details.fraudCheck;
 62→  if (fraudCheck?.primaryPhoto?.exifStatus === "ok") score += 5;
 63→  return Math.min(20, score);
 64→}
 65→
 66→function getGpsAccuracyScore(point: ProjectedPoint): number {
 67→  let score = 5;
 68→  const fraudCheck = point.details.fraudCheck;
 69→  if (fraudCheck?.primaryPhoto?.submissionGpsMatch === true) score += 5;
 70→  if (fraudCheck?.primaryPhoto?.ipGpsMatch === true) score += 5;
 71→  return Math.min(15, score);
 72→}
 73→
 74→function getReviewerApprovalScore(point: ProjectedPoint): number {
 75→  const reviewerApproved = point.details.reviewerApproved === true;
 76→  if (reviewerApproved) return 10;
 77→  if (point.eventsCount >= 2) return 3;
 78→  return 0;
 79→}
 80→
 81→function getFieldCompletenessScore(point: ProjectedPoint): number {
 82→  const enrichable = getVertical(point.category).enrichableFields;
 83→  if (enrichable.length === 0) return 0;
 84→  const filled = enrichable.filter((field) => hasValue(point.details[field])).length;
 85→  const ratio = filled / enrichable.length;
 86→  return Math.round(ratio * 10);
 87→}
 88→
 89→export function computeConfidenceFactors(point: ProjectedPoint, referenceDate: Date): ConfidenceFactors {
 90→  return {
 91→    recency: getRecencyScore(point.updatedAt, referenceDate),
 92→    sourceCount: getSourceCountScore(point.eventsCount),
 93→    photoEvidence: getPhotoEvidenceScore(point),
 94→    gpsAccuracy: getGpsAccuracyScore(point),
 95→    reviewerApproval: getReviewerApprovalScore(point),
 96→    fieldCompleteness: getFieldCompletenessScore(point),
 97→  };
 98→}
 99→
100→export function computeConfidenceScore(point: ProjectedPoint, referenceDate: Date): number {
101→  const factors = computeConfidenceFactors(point, referenceDate);
102→  const total = factors.recency
103→    + factors.sourceCount
104→    + factors.photoEvidence
105→    + factors.gpsAccuracy
106→    + factors.reviewerApproval
107→    + factors.fieldCompleteness;
108→  return clampScore(total);
109→}
