 46→function isoTimestamp(input: string | Date): string {
 47→  const parsed = input instanceof Date ? input : new Date(input);
 48→  if (Number.isNaN(parsed.getTime())) return new Date().toISOString();
 49→  return parsed.toISOString();
 50→}
 51→
 52→function normalizeZoneBounds(input: unknown): ZoneBounds {
 53→  const raw = input && typeof input === "object" ? (input as Record<string, unknown>) : {};
 54→  const south = Number(raw.south);
 55→  const west = Number(raw.west);
 56→  const north = Number(raw.north);
 57→  const east = Number(raw.east);
 58→  if (!Number.isFinite(south) || !Number.isFinite(west) || !Number.isFinite(north) || !Number.isFinite(east)) {
 59→    return { south: 0, west: 0, north: 0, east: 0 };
 60→  }
 61→  return { south, west, north, east };
 62→}
