 70→    zoneBounds: normalizeZoneBounds(row.zone_bounds),
 71→    assignedVerticals: (Array.isArray(row.assigned_verticals) ? row.assigned_verticals : []).filter((v): v is SubmissionCategory => isValidCategory(v)),
 72→    assignedDate: dateOnly(row.assigned_date),
 73→    dueDate: dateOnly(row.due_date),
 74→    status: row.status,
 75→    pointsExpected: Number(row.points_expected) || 0,
 76→    pointsSubmitted: Number(row.points_submitted) || 0,
 77→    completionRate: Number(row.completion_rate) || 0,
 78→    notes: row.notes ?? null,
 79→    createdAt: isoTimestamp(row.created_at),
 80→    updatedAt: isoTimestamp(row.updated_at),
 81→  };
 82→}
