 84→function normalizeDateInput(input: unknown): string | null {
 85→  if (typeof input !== "string") return null;
 86→  const trimmed = input.trim();
 87→  if (!/^\d{4}-\d{2}-\d{2}$/.test(trimmed)) return null;
 88→  const parsed = new Date(`${trimmed}T00:00:00.000Z`);
 89→  if (Number.isNaN(parsed.getTime())) return null;
 90→  return trimmed;
 91→}
