100→function normalizeStatus(input: unknown): CollectionAssignmentStatus | null {
101→  if (typeof input !== "string") return null;
102→  const normalized = input.trim().toLowerCase();
103→  if (normalized === "pending" || normalized === "in_progress" || normalized === "completed" || normalized === "expired") {
104→    return normalized;
105→  }
106→  return null;
107→}
108→
109→function normalizePointsExpected(input: unknown, fallback = 0): number {
110→  const value = typeof input === "number" ? input : Number(input);
111→  if (!Number.isFinite(value)) return fallback;
112→  return Math.max(0, Math.round(value));
113→}
