115→function normalizeAssignedVerticals(input: unknown): SubmissionCategory[] {
116→  if (!Array.isArray(input)) return [];
117→  const clean = input
118→    .map((value) => (typeof value === "string" ? value.trim() : ""))
119→    .filter((value): value is SubmissionCategory => isValidCategory(value));
120→  return Array.from(new Set(clean));
121→}
