123→async function refreshAssignmentProgress(): Promise<void> {
124→  await query(
125→    `
126→      UPDATE collection_assignments
127→      SET
128→        status = 'expired',
129→        updated_at = now()
130→      WHERE status IN ('pending', 'in_progress')
131→        AND due_date < CURRENT_DATE
132→    `,
133→  );
134→
135→  await query(
136→    `
137→      WITH computed AS (
138→        SELECT
139→          a.id,
140→          COUNT(pe.id)::int AS points_submitted
141→        FROM collection_assignments a
142→        LEFT JOIN point_events pe
143→          ON pe.user_id = a.agent_user_id
144→          AND pe.category = ANY(a.assigned_verticals)
145→          AND pe.created_at::date BETWEEN a.assigned_date AND a.due_date
146→          AND pe.latitude BETWEEN (a.zone_bounds->>'south')::double precision AND (a.zone_bounds->>'north')::double precision
147→          AND pe.longitude BETWEEN (a.zone_bounds->>'west')::double precision AND (a.zone_bounds->>'east')::double precision
148→        GROUP BY a.id
149→      )
150→      UPDATE collection_assignments a
151→      SET
152→        points_submitted = computed.points_submitted,
153→        status = CASE
154→          WHEN a.status = 'expired' THEN a.status
155→          WHEN a.points_expected > 0 AND computed.points_submitted >= a.points_expected THEN 'completed'
156→          WHEN computed.points_submitted > 0 AND a.status = 'pending' THEN 'in_progress'
157→          ELSE a.status
158→        END,
159→        updated_at = CASE
160→          WHEN a.points_submitted IS DISTINCT FROM computed.points_submitted
161→            OR (
162→              CASE
163→                WHEN a.status = 'expired' THEN a.status
164→                WHEN a.points_expected > 0 AND computed.points_submitted >= a.points_expected THEN 'completed'
165→                WHEN computed.points_submitted > 0 AND a.status = 'pending' THEN 'in_progress'
166→                ELSE a.status
167→              END
168→            ) IS DISTINCT FROM a.status
169→          THEN now()
170→          ELSE a.updated_at
171→        END
172→      FROM computed
173→      WHERE computed.id = a.id
174→    `,
175→  );
176→}
