250→export async function createAssignment(input: CollectionAssignmentCreateInput): Promise<CollectionAssignment> {
251→  const agentUserId = typeof input.agentUserId === "string" ? input.agentUserId.trim().toLowerCase() : "";
252→  if (!agentUserId) {
253→    throw new Error("agentUserId is required");
254→  }
255→
256→  const agentExists = await query<{ id: string }>(
257→    `SELECT id FROM user_profiles WHERE id = $1 LIMIT 1`,
258→    [agentUserId],
259→  );
260→  if (!agentExists.rows[0]) {
261→    throw new Error("Agent user was not found");
262→  }
263→
264→  const zoneId = typeof input.zoneId === "string" ? input.zoneId.trim().toLowerCase() : "";
265→  const zone = getCollectionZone(zoneId);
266→  if (!zone) {
267→    throw new Error("Invalid zoneId");
268→  }
269→
270→  const assignedVerticals = normalizeAssignedVerticals(input.assignedVerticals);
271→  if (!assignedVerticals.length) {
272→    throw new Error("At least one assigned vertical is required");
273→  }
274→
275→  const dueDate = normalizeDateInput(input.dueDate);
276→  if (!dueDate) {
277→    throw new Error("Invalid dueDate (expected YYYY-MM-DD)");
278→  }
279→
280→  const assignedDate = normalizeDateInput(input.assignedDate) ?? new Date().toISOString().slice(0, 10);
281→  const pointsExpected = normalizePointsExpected(input.pointsExpected, 0);
282→  const notes = normalizeNotes(input.notes);
283→
284→  const result = await query<AssignmentDbRow>(
285→    `
286→      INSERT INTO collection_assignments (
287→        agent_user_id,
288→        zone_id,
289→        zone_label,
290→        zone_bounds,
291→        assigned_verticals,
292→        assigned_date,
293→        due_date,
294→        points_expected,
295→        notes
296→      )
297→      VALUES ($1, $2, $3, $4::jsonb, $5::text[], $6::date, $7::date, $8, $9)
298→      RETURNING
299→        id,
300→        agent_user_id,
301→        zone_id,
302→        zone_label,
303→        zone_bounds,
304→        assigned_verticals,
305→        assigned_date,
306→        due_date,
307→        status,
308→        points_expected,
309→        points_submitted,
310→        completion_rate,
311→        notes,
312→        created_at,
313→        updated_at
314→    `,
315→    [agentUserId, zone.id, zone.label, JSON.stringify(zone.bounds), assignedVerticals, assignedDate, dueDate, pointsExpected, notes],
316→  );
317→
318→  const row = result.rows[0];
319→  if (!row) throw new Error("Unable to create assignment");
320→  return toCollectionAssignment(row);
321→}
