328→  if (!id) return null;
329→
330→  const updates: string[] = [];
331→  const values: unknown[] = [];
332→  let idx = 1;
333→
334→  if (input.status !== undefined) {
335→    const status = normalizeStatus(input.status);
336→    if (!status) throw new Error("Invalid assignment status");
337→    updates.push(`status = $${idx++}`);
338→    values.push(status);
339→  }
340→
341→  if (input.pointsSubmitted !== undefined) {
342→    const pointsSubmitted = normalizePointsExpected(input.pointsSubmitted, 0);
343→    updates.push(`points_submitted = $${idx++}`);
344→    values.push(pointsSubmitted);
345→  }
346→
347→  if (input.notes !== undefined) {
348→    updates.push(`notes = $${idx++}`);
349→    values.push(normalizeNotes(input.notes));
350→  }
351→
352→  if (!updates.length) {
353→    const existing = await query<AssignmentDbRow>(
354→      `
355→        SELECT
356→          id,
357→          agent_user_id,
358→          zone_id,
359→          zone_label,
360→          zone_bounds,
361→          assigned_verticals,
362→          assigned_date,
363→          due_date,
364→          status,
365→          points_expected,
366→          points_submitted,
367→          completion_rate,
368→          notes,
369→          created_at,
370→          updated_at
371→        FROM collection_assignments
372→        WHERE id = $1::uuid
373→        LIMIT 1
374→      `,
375→      [id],
376→    );
377→    const row = existing.rows[0];
378→    return row ? toCollectionAssignment(row) : null;
379→  }
380→
381→  values.push(id);
382→  const result = await query<AssignmentDbRow>(
383→    `
384→      UPDATE collection_assignments
385→      SET
386→        ${updates.join(", ")},
387→        updated_at = now()
388→      WHERE id = $${idx}::uuid
389→      RETURNING
390→        id,
391→        agent_user_id,
392→        zone_id,
393→        zone_label,
394→        zone_bounds,
395→        assigned_verticals,
396→        assigned_date,
397→        due_date,
398→        status,
399→        points_expected,
400→        points_submitted,
401→        completion_rate,
402→        notes,
403→        created_at,
404→        updated_at
405→    `,
406→    values,
407→  );
408→
409→  const row = result.rows[0];
410→  return row ? toCollectionAssignment(row) : null;
411→}
