444→export async function incrementAssignmentsForEvent(event: PointEvent): Promise<void> {
445→  const userId = typeof event.userId === "string" ? event.userId.trim().toLowerCase() : "";
446→  if (!userId) return;
447→  try {
448→    await query(
449→      `
450→        UPDATE collection_assignments
451→        SET
452→          points_submitted = points_submitted + 1,
453→          status = CASE
454→            WHEN points_expected > 0 AND points_submitted + 1 >= points_expected THEN 'completed'
455→            WHEN status = 'pending' THEN 'in_progress'
456→            ELSE status
457→          END,
458→          updated_at = now()
459→        WHERE agent_user_id = $1
460→          AND $2 = ANY(assigned_verticals)
461→          AND $3::date BETWEEN assigned_date AND due_date
462→          AND $4::double precision BETWEEN (zone_bounds->>'south')::double precision AND (zone_bounds->>'north')::double precision
463→          AND $5::double precision BETWEEN (zone_bounds->>'west')::double precision AND (zone_bounds->>'east')::double precision
464→          AND status IN ('pending', 'in_progress')
465→      `,
466→      [userId, event.category, event.createdAt, event.location.latitude, event.location.longitude],
467→    );
468→  } catch (error) {
469→    const code = (error as { code?: unknown } | null)?.code;
470→    if (code === "42P01") return;
471→    throw error;
472→  }
473→}
