22→export async function buildReadableEvents(): Promise<PointEvent[]> {
23→  const merged = await buildContributionEvents();
24→  const seenExternalIds = new Set(
25→    merged
26→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
27→      .filter((value) => value.length > 0),
28→  );
29→  const seenPointIds = new Set(merged.map((event) => event.pointId));
30→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
31→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
32→    if (externalId && seenExternalIds.has(externalId)) continue;
33→    if (seenPointIds.has(seedEvent.pointId)) continue;
34→    merged.push(seedEvent);
35→    if (externalId) seenExternalIds.add(externalId);
36→    seenPointIds.add(seedEvent.pointId);
37→  }
38→  return merged;
39→}
